#include<iostream>
using namespace std ;
bool q(int n) {
	for (int i=2; i*i<=n; i++) {
		if(n%i==0) {
			return 0;
		}
	}
	return 1 ;
}
int sum,cnt;
int main () {
	int l;
	cin>>l;
	for(int i=2;; i++) {
		if (q(i)==1) {
			cnt++;
			sum+=i ;
			if(sum>l) {
				break;
			} else {
				cout<<i<<endl ;
			}
		}
	}
	cout<<cnt-1;
	return 0;
}
